WrestlingAreaEvent = class("WrestlingAreaEvent", BaseAreaEvent)

function WrestlingAreaEvent:onEnterArea(player)
    LogUtil.log("WrestlingAreaEvent:onEnterArea " .. tostring(player.userId))
    player.property.wrestlingKill = 0
    player.property.isWrestling = true
end

function WrestlingAreaEvent:onLeaveArea(player)
    LogUtil.log("WrestlingAreaEvent:onLeaveArea " .. tostring(player.userId))
    player.property.wrestlingKill = 0
    player.property.isWrestling = false
end

function WrestlingAreaEvent:doReward()
    local rewardList = {}

    for _, vPlayer in pairs(PlayerManager:getPlayers()) do
        if vPlayer:isEntityAlive() and MathUtil:checkPosInRect(vPlayer:getPosition(), Rect.new(self.config.areaRange[1].x, self.config.areaRange[1].y,
                self.config.areaRange[2].x, self.config.areaRange[2].y))
                and vPlayer.property.muscleMass >= self.config.needMuscle then
            table.insert(rewardList, vPlayer)
        end
    end

    local winner = nil
    local maxKill = -1
    local num = math.ceil(self.config.rewardNum / #rewardList) --平分
    for i = 1, #rewardList do
        local player = rewardList[i]
        player:doReward(self.config.rewardType, num)
        if player.property.wrestlingKill > maxKill then
            maxKill = player.property.wrestlingKill
            winner = player
        end
        --传送回初始位置
        player:teleportPos(player:randomInitPos())
    end

    --胜利广播
    if winner then
        LogUtil.log(string.format("WrestlingAreaEvent:doReward %s %d", winner.name, maxKill))

        local params = { winnerName = winner.name }
        local data = DataBuilder.new():fromTable(params):getData()
        PacketSender:broadCastLuaCommonData("WrestlingNotification", data)

        --播放胜利特效
        local config = EffectConfig:getEffectConfig(self.config.winEffect)
        if config then
            winner:addCustomEffect("WrestlingWinEffect", config.name, config.liveTime)
        end

        --播放ko特效
        PacketSender:sendLuaCommonData(winner.rakssid, "WrestlingKOEffect", "")
    end
end

return WrestlingAreaEvent